function countVowelStrings(n) {
    const dp = [1, 1, 1, 1, 1];

    for (let i = 1; i < n; i++) {
        for (let j = 3; j >= 0; j--) {
            dp[j] += dp[j + 1];
        }
    }

    return dp.reduce((a, b) => a + b, 0);
}
